impl Solution { pub fn remove_stones(black_s: Vec<Vec<i32>>) -> i32 { let mut black_f = std::collections::HashMap::new(); fn black_find(i: i32, f: &mut std::collections::HashMap<i32, i32>) -> i32 { if *f.entry(i).or_insert(i) == i { i } else { let next = f[&i]; let res = black_find(next, f); f.insert(i, res); res } } for s in &black_s { let (r, c) = (black_find(s[0], &mut black_f), black_find(!s[1], &mut black_f)); if r != c { black_f.insert(r, c); } } let black_n = black_s.len() as i32; let black_unique = black_f.keys().filter(|&&k| black_f[&k] == k).count() as i32; black_n - black_unique } }